1	/**
2	 * Auxilio Visitor — Google Calendar add-on (card-first).
3	 *
4	 * The whole host flow lives in this card; it calls office-ops-engine over HTTPS.
5	 * Engine contract: ../office-ops-engine/spec/2026-06-16_calendar_addon_register_endpoint.md
6	 *
7	 * Apps Script (GAS, V8) — flat global scope, no imports/modules.
8	 * First version: push with clasp, then refine in the Apps Script editor (it can run
9	 * and log there; it can't be run from the monorepo).
10	 */
11	
12	// Engine base URL. Default = the local-tunnel domain (npm run backendtunnel).
13	// Must also be listed in appsscript.json → urlFetchWhitelist.
14	var ENGINE_BASE = 'https://unyearning-olympia-unclimactic.ngrok-free.dev';
15	
16	// Appointy logo embedded as a base64 data URI (gradient original from appointy.svg).
17	// Source: appointy.svg (copied from visitor-web/public/, also in this repo).
18	// Used by setImageUrl() in all card headers.
19	var ADDON_ICON_URL = 'data:image/svg+xml;base64,REDACTED';
20	
21	// Primary brand colour — used for filled buttons and accent text.
22	var BRAND_COLOR = '#92288E';
23	
24	// Circular "workspace building" avatar (Lucide `building` on a muted grey circle),
25	// shown in place of the photo avatar for INTERNAL colleagues so the host can tell at
26	// a glance who's a same-office teammate (toggle-off by default) vs an outside guest.
27	var INTERNAL_ICON_URL = 'data:image/svg+xml;base64,REDACTED';
28	
29	// ── Triggers ──────────────────────────────────────────────
30	function onCalendarEventOpen(e) { return [buildVisitorCard_(e)]; }
31	function onCalendarEventUpdate(e) { return [buildVisitorCard_(e)]; }
32	
33	// Serves the branded icon SVG at ?asset=logo. ContentService.MimeType.XML is the
34	// closest available type to image/svg+xml in GAS. The manifest logoUrl below points
35	// to visitor-web instead, which nginx serves with the correct image/svg+xml header.
36	function doGet(e) {
37	  if (e && e.parameter && e.parameter.asset === 'logo') {
38	    var b64 = ADDON_ICON_URL.split(',')[1];
39	    var svgText = Utilities.newBlob(Utilities.base64Decode(b64)).getDataAsString();
40	    return ContentService.createTextOutput(svgText).setMimeType(ContentService.MimeType.XML);
41	  }
42	  return ContentService.createTextOutput('Auxilio Workspace Add-on');
43	}
44	
45	// Three-dot menu → Sign out.
46	// NOTE: we deliberately do NOT call ScriptApp.invalidateAuth() — invalidating auth
47	// breaks every subsequent add-on invocation (incl. re-clicking this very item) with
48	// "Unspecified error invoking the add-on", because the platform can't run any
49	// function once authorization is cleared. A Calendar add-on also has no login page
50	// we can navigate to (Google only shows the consent prompt automatically on the next
51	// authorized open). So sign-out routes the user to the real, linkable destination:
52	// the Google Account permissions page, where they can remove access / switch account.
53	// Removing access there forces full re-consent the next time they open the add-on.
54	function onSignOut(e) {
55	  var card = CardService.newCardBuilder()
56	    .setHeader(CardService.newCardHeader()
57	      .setTitle('Sign out')
58	      .setImageUrl(ADDON_ICON_URL))
59	    .addSection(CardService.newCardSection()
60	      .addWidget(CardService.newDecoratedText()
61	        .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PERSON))
62	        .setText('Switch account or re-grant access')
63	        .setBottomLabel('Remove Auxilio Visitor from your Google account, then reopen the add-on — you\'ll be asked to sign in and grant access again.')
64	        .setWrapText(true))
65	      .addWidget(CardService.newTextButton()
66	        .setText('Manage access')
67	        .setTextButtonStyle(CardService.TextButtonStyle.FILLED)
68	        .setOpenLink(CardService.newOpenLink()
69	          .setUrl('https://myaccount.google.com/permissions'))))
70	    .build();
71	  return CardService.newUniversalActionResponseBuilder()
72	    .displayAddOnCards([card])
73	    .build();
74	}
75	
76	function onHomepage(e) {
77	  var introSection = CardService.newCardSection()
78	    .addWidget(CardService.newTextParagraph()
79	      .setText('Open a calendar event and add guest to register visitor passes.'));
80	
81	  var howSection = CardService.newCardSection()
82	    .setHeader('How it works')
83	    .addWidget(CardService.newDecoratedText()
84	      .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PERSON))
85	      .setText('Choose who gets a pass')
86	      .setBottomLabel('Toggle guests on or off from the event\'s attendee list.')
87	      .setWrapText(true))
88	    .addWidget(CardService.newDecoratedText()
89	      .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.INVITE))
90	      .setText('Review and send')
91	      .setBottomLabel('Edit names and phone numbers, preview the invite email, then send.')
92	      .setWrapText(true))
93	    .addWidget(CardService.newDecoratedText()
94	      .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.TICKET))
95	      .setText('Manage anytime')
96	      .setBottomLabel('Cancel or resend passes by toggling them off and on.')
97	      .setWrapText(true));
98	
99	  var autoSyncSection = CardService.newCardSection()
100	    .addWidget(CardService.newDecoratedText()
101	      .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.STAR))
102	      .setText('Auto-sync')
103	      .setBottomLabel('Move or cancel a meeting event and passes update automatically.')
104	      .setWrapText(true));
105	
106	  return CardService.newCardBuilder()
107	    .setHeader(CardService.newCardHeader()
108	      .setTitle('Auxilio Visitor')
109	      .setSubtitle('Manage visitors from your calendar')
110	      .setImageUrl(ADDON_ICON_URL))
111	    .addSection(introSection)
112	    .addSection(howSection)
113	    .addSection(autoSyncSection)
114	    .build();
115	}
116	
117	// ── Engine HTTP ───────────────────────────────────────────
118	function engineFetch_(path, method, payload) {
119	  var options = {
120	    method: method,
121	    contentType: 'application/json',
122	    muteHttpExceptions: true,
123	    headers: {
124	      Authorization: 'Bearer ' + ScriptApp.getIdentityToken(),
125	      'ngrok-skip-browser-warning': 'true'
126	    }
127	  };
128	  if (payload) options.payload = JSON.stringify(payload);
129	  var res = UrlFetchApp.fetch(ENGINE_BASE + path, options);
130	  var json = {};
131	  try { json = JSON.parse(res.getContentText()); } catch (err) {}
132	  return { code: res.getResponseCode(), json: json };
133	}
134	
135	// Resolve attendees + (best-effort) iCalUID/title/times for the open event.
136	// Attendees come from the add-on payload (currentEventAccess) — no API call needed.
137	// The Calendar API lookup enriches with the canonical iCalUID + title/times so the
138	// engine dedups with the .ics/OAuth paths; if it fails we fall back to the event id
139	// as the key so the flow still works.
140	function loadEvent_(e) {
141	  var cal = e.calendar || {};
142	  var calendarId = cal.calendarId;
143	  var eventId = cal.id;
144	  var payloadAtt = cal.attendees || [];
145	  var info = {
146	    iCalUid: eventId,
147	    providerEventId: eventId,
148	    keySource: 'eventId',
149	    title: '',
150	    start: null,
151	    end: null,
152	    attendees: mapAttendees_(payloadAtt),
153	    debug: ''
154	  };
155	  var ev = fetchEventWithRetry_(calendarId, eventId);
156	  info.gotEvent = !!ev;
157	  if (ev) {
158	    if (ev.iCalUID) { info.iCalUid = ev.iCalUID; info.keySource = 'iCalUID'; }
159	    info.title = ev.summary || '';
160	    info.start = ev.start ? (ev.start.dateTime || ev.start.date) : null;
161	    info.end = ev.end ? (ev.end.dateTime || ev.end.date) : null;
162	    var apiAtt = mapAttendees_(ev.attendees);
163	    if (info.attendees.length === 0 && apiAtt.length > 0) info.attendees = apiAtt;
164	  }
165	  info.debug = 'got=' + (!!ev) + ' key=' + info.keySource + ' start=' + (info.start || 'null') +
166	    ' cal=' + (calendarId || '?') + ' guests=' + info.attendees.length +
167	    (info.gotEvent ? '' : ' err=' + (_lastEventFetchErr || 'none'));
168	  return info;
169	}
170	
171	// Resolve the event from the Calendar API, tolerating transient 404s. A freshly
172	// created event is eventually-consistent — Events.get can 404 for a second or two
173	// after the user adds it — and this is our ONLY source of event start/end (the add-on
174	// payload carries attendees but no times). So a miss here means a draft saved without
175	// times and a send that fails with EVENT_TIME_MISSING. Retry with backoff (~2.7s
176	// total) across the event's calendar and the primary calendar. Returns the event or null.
177	var _lastEventFetchErr = '';
178	function fetchEventWithRetry_(calendarId, eventId) {
179	  _lastEventFetchErr = '';
180	  var targets = [];
181	  if (calendarId) targets.push(calendarId);
182	  if (calendarId !== 'primary') targets.push('primary');
183	  // Common case (a saved, propagated event) returns on the first get with no sleep.
184	  // The retries only cover a just-created event that's still eventually-consistent;
185	  // ~0.85s total is enough to catch the usual ~1s propagation without making every
186	  // unsaved-event open feel sluggish (the card shows a "save first" banner anyway,
187	  // and onSaveAndSend re-resolves the time before the actual send).
188	  var backoffs = [250, 600]; // waits AFTER attempts 0,1 (3 attempts total)
189	  for (var attempt = 0; attempt <= backoffs.length; attempt++) {
190	    for (var t = 0; t < targets.length; t++) {
191	      try {
192	        var ev = Calendar.Events.get(targets[t], eventId);
193	        if (ev) return ev;
194	      } catch (err) {
195	        // Capture WHY (auth/scope vs 404) — a persistent failure here is the root of
196	        // "Could not read the event time"; the message tells us scope vs not-found.
197	        _lastEventFetchErr = (err && err.message ? String(err.message) : String(err)).slice(0, 140);
198	      }
199	    }
200	    if (attempt < backoffs.length) Utilities.sleep(backoffs[attempt]);
201	  }
202	  return null;
203	}
204	
205	// Per-guest avatar: Gravatar keyed on the email (real photo if they have one),
206	// falling back to a coloured initials avatar (ui-avatars) when they don't. Rendered
207	// as a circular image icon. Image URLs are fetched by Google's client, so they
208	// don't need urlFetchWhitelist.
209	function avatarIcon_(email, name) {
210	  var initials = (name || email || '?').trim().charAt(0).toUpperCase() || '?';
211	  var fallback = 'https://ui-avatars.com/api/?name=' + encodeURIComponent(initials) +
212	    '&size=64&background=92288E&color=ffffff&bold=true';
213	  var url = 'https://www.gravatar.com/avatar/' + md5Hex_((email || '').trim().toLowerCase()) +
214	    '?s=64&d=' + encodeURIComponent(fallback);
215	  return CardService.newIconImage()
216	    .setIconUrl(url)
217	    .setImageCropType(CardService.ImageCropType.CIRCLE);
218	}
219	
220	// Circular building icon for internal colleagues (see INTERNAL_ICON_URL).
221	function buildingIcon_() {
222	  return CardService.newIconImage()
223	    .setIconUrl(INTERNAL_ICON_URL)
224	    .setImageCropType(CardService.ImageCropType.CIRCLE);
225	}
226	
227	// Minimal MD5 → lowercase hex (Gravatar needs MD5 of the email).
228	function md5Hex_(str) {
229	  var bytes = Utilities.computeDigest(Utilities.DigestAlgorithm.MD5, str, Utilities.Charset.UTF_8);
230	  var hex = '';
231	  for (var i = 0; i < bytes.length; i++) {
232	    var b = (bytes[i] + 256) % 256;
233	    hex += (b < 16 ? '0' : '') + b.toString(16);
234	  }
235	  return hex;
236	}
237	
238	function mapAttendees_(list) {
239	  return (list || [])
240	    .filter(function (a) { return a && a.email && !a.self && !a.organizer && !a.resource; })
241	    .map(function (a) {
242	      // Google often sets displayName = the email for non-contacts → treat as no name.
243	      var nm = (a.displayName && a.displayName !== a.email) ? a.displayName : '';
244	      return { email: a.email, name: nm };
245	    });
246	}
