250	function statusLabel_(g) {
251	  if (g.status === 'sent')      return '<font color="#34a853">Pass sent</font>';
252	  if (g.status === 'cancelled') return '<font color="#ea4335">Cancelled — toggle on to resend</font>';
253	  if (g.include === false) {
254	    // Internal colleagues are off by default ON PURPOSE — say so instead of a bare
255	    // "No pass" that reads like something's missing.
256	    return g.internal
257	      ? '<font color="#5f6368">Internal</font>'
258	      : '<font color="#9aa0a6">No pass</font>';
259	  }
260	  return '<font color="' + BRAND_COLOR + '">Will get a pass</font>';
261	}
