263	// Returns a coloured stat line: "3 guests · 2 sent · 1 pending"
264	function buildStatLine_(roster) {
265	  var total = roster.length;
266	  var sent = 0, pending = 0, cancelled = 0;
267	  for (var i = 0; i < roster.length; i++) {
268	    var g = roster[i];
269	    if (g.status === 'sent') sent++;
270	    else if (g.status === 'cancelled') cancelled++;
271	    else if (g.include !== false) pending++;
272	  }
273	  var parts = [total + (total === 1 ? ' guest' : ' guests')];
274	  if (sent)      parts.push('<font color="#34a853">' + sent + ' sent</font>');
275	  if (pending)   parts.push('<font color="' + BRAND_COLOR + '">' + pending + ' pending</font>');
276	  if (cancelled) parts.push('<font color="#ea4335">' + cancelled + ' cancelled</font>');
277	  return parts.join('  ·  ');
278	}
