291	// Returns "Meeting title · Wed 18 Jun, 3:00 PM" for the card subtitle.
292	function formatEventSubtitle_(ev) {
293	  if (!ev.start) return ev.title || '';
294	  try {
295	    var d = new Date(ev.start);
296	    var day  = d.toLocaleDateString('en-IN', { weekday: 'short', day: 'numeric', month: 'short' });
297	    var time = d.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit', hour12: true });
298	    var datePart = day + ', ' + time;
299	    return ev.title ? ev.title + '  ·  ' + datePart : datePart;
300	  } catch (err) {
301	    return ev.title || '';
302	  }
