308	  // network call. Keeps empty events snappy so the loader never lingers.
309	  var cal = e.calendar || {};
310	  if (mapAttendees_(cal.attendees).length === 0) {
311	    return CardService.newCardBuilder()
312	      .setHeader(CardService.newCardHeader()
