332	  if (res.code === 401) return errorCard_('Not authorized. Check the engine\'s AUXILIO_WORKSPACE_OAUTH_CLIENT_ID.');
333	  if (res.code === 403) return errorCard_('Your domain is not allowed to host visits.');
334	  if (res.code !== 200) return errorCard_('Engine error ' + res.code + '. Try refreshing the page.');
