484	// ── Actions ───────────────────────────────────────────────
485	// Same derivation the engine uses, so we can tell an auto-derived name from a real one.
486	function cardDeriveName_(email) {
487	  var local = (email.split('@')[0] || email);
488	  return local.replace(/[._-]+/g, ' ').replace(/\b\w/g, function (c) { return c.toUpperCase(); }).trim() || email;
489	}
490	
491	// Contact-name lookups are the heaviest part of a fresh card open, so we cache each
492	// resolved name (incl. "no match", to avoid re-querying non-contacts) per user in
493	// CacheService. A repeat open of any event with the same guest is then zero network.
494	// TTL 6h: long enough that a meeting's roster never re-pays, short enough to pick up
495	// a newly-added contact within a day. Key is lowercased email (per-user cache).
496	var _CONTACT_CACHE_TTL = 21600; // 6h, in seconds
497	function _contactCacheKey_(email) { return 'cn_' + (email || '').toLowerCase(); }
498	
499	// searchContacts/otherContacts.search need a one-time warmup (empty query) so the
500	// server-side index is populated before the real query. Done once per execution.
501	var _peopleWarmed = false;
502	function warmPeople_(headers, base) {
503	  if (_peopleWarmed) return;
504	  _peopleWarmed = true;
505	  try {
506	    UrlFetchApp.fetchAll([
507	      { url: base + 'people:searchContacts?query=&readMask=names,emailAddresses', headers: headers, muteHttpExceptions: true },
508	      { url: base + 'otherContacts:search?query=&readMask=names,emailAddresses', headers: headers, muteHttpExceptions: true }
509	    ]);
510	  } catch (err) {}
511	  Utilities.sleep(120); // brief settle so the freshly-warmed index is queryable
512	}
513	
514	// Pull the display name for `email` out of a People search response, or '' if no
515	// result actually matches that address.
516	function extractPeopleName_(resp, email) {
517	  if (!resp || resp.getResponseCode() !== 200) return '';
518	  var results;
519	  try { results = (JSON.parse(resp.getContentText()).results) || []; }
520	  catch (err) { return ''; }
521	  for (var i = 0; i < results.length; i++) {
522	    var person = results[i].person || {};
523	    var emails = person.emailAddresses || [];
524	    var match = emails.some(function (em) { return (em.value || '').toLowerCase() === email.toLowerCase(); });
525	    if (match && person.names && person.names.length) return person.names[0].displayName || '';
526	  }
527	  return '';
528	}
529	
530	// Resolve display names for several emails in ONE parallel batch (searchContacts +
531	// otherContacts.search per email via UrlFetchApp.fetchAll) instead of 2 serial calls
532	// each. Returns a map of lowercased email → name (absent when no contact matched).
533	function batchResolveNames_(emails) {
534	  var out = {};
535	  if (!emails.length) return out;
536	  var headers = { Authorization: 'Bearer ' + ScriptApp.getOAuthToken() };
537	  var base = 'https://people.googleapis.com/v1/';
538	  warmPeople_(headers, base);
539	  var requests = [], meta = [];
540	  for (var i = 0; i < emails.length; i++) {
541	    var q = encodeURIComponent(emails[i]);
542	    requests.push({ url: base + 'people:searchContacts?query=' + q + '&readMask=names,emailAddresses', headers: headers, muteHttpExceptions: true });
543	    meta.push(emails[i]);
544	    requests.push({ url: base + 'otherContacts:search?query=' + q + '&readMask=names,emailAddresses', headers: headers, muteHttpExceptions: true });
545	    meta.push(emails[i]);
546	  }
547	  var responses;
548	  try { responses = UrlFetchApp.fetchAll(requests); }
549	  catch (err) { return out; }
550	  for (var r = 0; r < responses.length; r++) {
551	    var key = meta[r].toLowerCase();
552	    if (out[key]) continue; // already matched from this email's other source
553	    var name = extractPeopleName_(responses[r], meta[r]);
554	    if (name) out[key] = name;
555	  }
556	  return out;
557	}
558	
559	// For each guest whose name is still auto-derived, fill in the real contact name and
560	// PATCH it onto the draft (so the engine remembers it too). Cache hits skip the
561	// network entirely; only genuine misses hit the People API, all in one batch. Mutates
562	// roster.
563	function resolveAndStoreNames_(iCalUid, roster) {
564	  var cache = CacheService.getUserCache();
565	  var pending = [];   // roster entries still showing an auto-derived name
566	  var toLookup = [];  // emails with no cached answer → need a network lookup
567	  for (var i = 0; i < roster.length; i++) {
568	    var g = roster[i];
569	    if (g.name && g.name !== cardDeriveName_(g.email)) continue; // already a real name
570	    pending.push(g);
571	    var cached = cache.get(_contactCacheKey_(g.email));
572	    if (cached === null) toLookup.push(g.email); // unknown → look up
573	    else if (cached) g.name = cached;            // '' = known non-contact, leave derived
574	  }
575	
576	  if (toLookup.length) {
577	    var resolved = batchResolveNames_(toLookup);
578	    for (var j = 0; j < toLookup.length; j++) {
579	      var name = resolved[toLookup[j].toLowerCase()] || '';
580	      cache.put(_contactCacheKey_(toLookup[j]), name, _CONTACT_CACHE_TTL); // cache hits AND misses
581	    }
582	    for (var k = 0; k < pending.length; k++) {
583	      var pg = pending[k];
584	      var rn = resolved[pg.email.toLowerCase()];
585	      if (rn) pg.name = rn; // reflect immediately in this render
586	    }
587	  }
588	
589	  var patches = [];
590	  for (var m = 0; m < pending.length; m++) {
591	    var p = pending[m];
592	    if (p.name && p.name !== cardDeriveName_(p.email)) patches.push({ email: p.email, name: p.name });
593	  }
594	  if (patches.length) {
595	    engineFetch_('/api/visitor/calendar/addon/draft', 'PATCH', { iCalUid: iCalUid, patch: { guests: patches } });
596	  }
597	}
