599	// Unsaved-event CTA: we can't read the event time until it's saved (Google doesn't
600	// put it in the add-on payload), so remind the host to save. Saving fires the
601	// eventUpdateTrigger, which re-renders this card with a working Review & send.
602	function onNeedsSave(e) {
603	  return notify_('Save the event first (click Save). The panel will update so you can send passes.');
604	}
