606	// Review step: persist edits, then push a textual confirm card. Cards can't
607	// render HTML inline (that's the "Preview email" overlay link), so the review
608	// here is the recipient list + what will happen — the guard before sending.
609	function onReviewSend(e) {
610	  var iCalUid = e.parameters.iCalUid;
611	  patchFromForm_(iCalUid, e); // persist toggles/names/phones BEFORE leaving the form card
612	  var emails = (e.parameters.emails || '').split(',').filter(Boolean_);
613	  var inputs = formInputs_(e);
614	  var included = [];
615	  var excluded = [];
616	  for (var i = 0; i < emails.length; i++) {
617	    var em = emails[i];
618	    var on = formValue_(inputs['inc_' + em]) === 'on';
619	    var name = formValue_(inputs['name_' + em]) || em;
620	    (on ? included : excluded).push({ email: em, name: name });
621	  }
622	  if (!included.length) return notify_('Turn on at least one guest before sending.');
623	  return CardService.newActionResponseBuilder()
624	    .setNavigation(CardService.newNavigation().pushCard(buildConfirmCard_(e.parameters, included, excluded)))
