628	function buildConfirmCard_(params, included, excluded) {
629	  // Thread the first included guest to the confirm card's actions — the per-guest
630	  // switches don't exist here, so onPreview can't re-derive the target from the form.
631	  params.previewEmail = included.length ? included[0].email : '';
632	  var card = CardService.newCardBuilder()
