654	  // Email section: template picker (only when there's a real choice) + preview. The
655	  // picker is per-send (one template for the whole batch); preview opens the REAL
656	  // branded HTML for the first included guest. Both read/write the same draft, so
657	  // pick → preview → send stays consistent.
658	  var templates = [];
659	  try { templates = JSON.parse(params.templates || '[]'); } catch (err) { templates = []; }
660	  var emailSec = CardService.newCardSection().setHeader('Email');
661	  if (templates.length >= 2) {
662	    var picker = CardService.newSelectionInput()
663	      .setType(CardService.SelectionInputType.DROPDOWN)
664	      .setTitle('Template')
665	      .setFieldName('email_template')
666	      // Persist the choice to the draft the moment it changes. The Preview link below
667	      // is pre-baked at card-build time, and the engine renders preview-html from the
668	      // draft LIVE — so persisting on change is what keeps the (unchanged) link
669	      // showing the newly-picked template, with no round-trip on the Preview click.
670	      .setOnChangeAction(CardService.newAction()
671	        .setFunctionName('onConfirmTemplateChange')
672	        .setParameters({ iCalUid: params.iCalUid, emails: params.emails }));
673	    var current = params.currentTemplate || '';
674	    for (var t = 0; t < templates.length; t++) {
675	      var tmpl = templates[t];
676	      var selected = current ? (tmpl.key === current) : (tmpl.isDefault === true);
677	      picker.addItem(tmpl.name || tmpl.key, tmpl.key, selected);
678	    }
679	    emailSec.addWidget(picker);
680	  }
681	  // Pre-bake the preview link NOW (mint the signed token at card-build time) and carry
682	  // it on the button via setOpenLink. That opens the popup directly on the user's click
683	  // instead of after a server round-trip (setOnClickAction → onPreview), which is what
684	  // the browser popup blocker was killing. Fall back to the action handler only if we
685	  // couldn't mint the link (e.g. token fetch failed) — that path may still get blocked.
686	  var previewBtn = CardService.newTextButton().setText('Preview email');
687	  var pvUrl = previewUrl_(params.iCalUid, params.previewEmail);
688	  if (pvUrl) {
689	    previewBtn.setOpenLink(CardService.newOpenLink()
690	      .setUrl(pvUrl)
691	      .setOpenAs(CardService.OpenAs.OVERLAY)
692	      .setOnClose(CardService.OnClose.NOTHING));
693	  } else {
694	    previewBtn.setOnClickAction(CardService.newAction().setFunctionName('onPreview').setParameters(params));
695	  }
696	  emailSec.addWidget(previewBtn);
697	  card.addSection(emailSec);
698	
699	  card.setFixedFooter(CardService.newFixedFooter()
700	    .setPrimaryButton(CardService.newTextButton()
701	      .setText('Send passes')
702	      .setTextButtonStyle(CardService.TextButtonStyle.FILLED)
703	      .setBackgroundColor(BRAND_COLOR)
704	      .setOnClickAction(CardService.newAction().setFunctionName('onSaveAndSend').setParameters(params)))
705	    .setSecondaryButton(CardService.newTextButton()
706	      .setText('Back')
707	      .setOnClickAction(CardService.newAction().setFunctionName('onConfirmBack').setParameters(params))));
708	  return card.build();
709	}
