717	function onSaveAndSend(e) {
718	  var iCalUid = e.parameters.iCalUid;
719	  // Toggles/names/phones were already persisted by onReviewSend on the ROSTER card.
720	  // This runs from the CONFIRM card, which has none of those widgets — re-running
721	  // patchFromForm_ here would read empty inputs and wipe every guest to include=false
722	  // (the "No changes / No pass" bug). Only the (optional) template picker lives here.
723	  patchTemplateFromForm_(iCalUid, e);
724	  // Re-resolve event times here and send them along: if the draft-open missed them
725	  // (flaky Events.get on a just-created event), the draft would have no start/end and
726	  // the send would fail with EVENT_TIME_MISSING. Passing fresh times lets the engine
727	  // self-correct the draft instead of forcing the host to reopen.
728	  var ev = loadEvent_(e);
729	  // Times come only from Calendar.Events.get (the payload has none). If we still can't
730	  // read them, say exactly why instead of the engine's generic message — `got=false`
731	  // means the API call itself failed (scope/Advanced-Service/permission, not a timing
732	  // blip); `got=true start=null` means the event genuinely has no start.
733	  if (!ev.start || !ev.end) {
734	    // A 'Not Found' from Calendar.Events.get means the event isn't saved/propagated
735	    // yet — the panel shows attendees from the payload, but the event record (the only
736	    // source of start/end) doesn't exist server-side. Tell the host plainly.
737	    if (ev.debug.indexOf('Not Found') >= 0 || !ev.gotEvent) {
738	      return notify_('Save the event first (click Save), then reopen this panel and send. The pass time comes from the saved event.');
739	    }
740	    return notify_('Could not read the event time. Diagnostic: ' + ev.debug);
741	  }
742	  var res = engineFetch_('/api/visitor/calendar/addon/send', 'POST', {
743	    iCalUid: iCalUid, start: ev.start, end: ev.end
744	  });
745	  var msg;
746	  if (res.code === 200) {
747	    var sent = (res.json.created || []).length;
748	    var cancelled = (res.json.cancelled || []).length;
749	    var failed = res.json.failed || [];
750	    if (failed.length) {
751	      // Surface WHY a pass couldn't be sent (most often: event time in the past)
752	      // instead of silently leaving the guest pending.
753	      var reason = (failed[0] && failed[0].reason) || 'could not be sent';
754	      msg = "Couldn't send " + failed.length + ' pass' + (failed.length > 1 ? 'es' : '') + ': ' + reason;
755	    } else {
756	      var parts = [];
757	      if (sent) parts.push(sent + ' sent');
758	      if (cancelled) parts.push(cancelled + ' cancelled');
759	      msg = parts.length ? ('Passes updated: ' + parts.join(', ') + '.') : 'No changes.';
760	    }
761	  } else {
762	    msg = 'Update failed (' + res.code + ').';
763	  }
764	  // Re-render so the card switches to Manage mode and shows fresh statuses.
765	  return CardService.newActionResponseBuilder()
766	    .setNotification(CardService.newNotification().setText(msg))
767	    .setNavigation(CardService.newNavigation().updateCard(buildVisitorCard_(e)))
768	    .build();
769	}
770	
771	function onPreview(e) {
772	  var iCalUid = e.parameters.iCalUid;
773	  // Runs from the CONFIRM card (no toggle/name/phone widgets) — persist only the
774	  // template choice; never re-derive include/name/phone here (would wipe the roster).
775	  patchTemplateFromForm_(iCalUid, e);
776	  // The included guests were already resolved on the roster card; onReviewSend threads
777	  // the first one through as previewEmail (the switches aren't on this card to read).
778	  var target = e.parameters.previewEmail || '';
779	  if (!target) return notify_('Turn on at least one guest to preview their email.');
780	
781	  var pv = engineFetch_('/api/visitor/calendar/addon/preview', 'POST', { iCalUid: iCalUid, visitorEmail: target });
782	  if (pv.code !== 200 || !pv.json.previewToken) return notify_('Preview failed (' + pv.code + ').');
783	
784	  // Open the REAL branded HTML in a popup overlay (the card can't render HTML).
785	  var url = ENGINE_BASE + '/api/visitor/calendar/addon/preview-html?t=' + encodeURIComponent(pv.json.previewToken);
786	  return CardService.newActionResponseBuilder()
787	    .setOpenLink(CardService.newOpenLink()
788	      .setUrl(url)
789	      .setOpenAs(CardService.OpenAs.OVERLAY)
790	      .setOnClose(CardService.OnClose.NOTHING))
791	    .build();
792	}
793	
794	// Mint a preview-html URL (with a fresh signed token) at card-build time so the
795	// "Preview email" button can carry it via setOpenLink and open on the click itself
796	// — dodging the popup blocker that hits round-trip (setOnClickAction) opens. Returns
797	// '' if we can't mint a token, so the caller can fall back to the onPreview handler.
798	function previewUrl_(iCalUid, visitorEmail) {
799	  if (!iCalUid || !visitorEmail) return '';
800	  var pv = engineFetch_('/api/visitor/calendar/addon/preview', 'POST', { iCalUid: iCalUid, visitorEmail: visitorEmail });
801	  if (pv.code !== 200 || !pv.json.previewToken) return '';
802	  return ENGINE_BASE + '/api/visitor/calendar/addon/preview-html?t=' + encodeURIComponent(pv.json.previewToken);
803	}
804	
805	// Template dropdown changed on the confirm card: persist the new choice to the draft.
806	// The Preview link is pre-baked and the token is template-agnostic (preview-html reads
807	// the draft live), so persisting here is all that's needed — no card rebuild, no new
808	// URL. Stay silent on success; only speak up if the persist failed.
809	function onConfirmTemplateChange(e) {
810	  var res = patchTemplateFromForm_(e.parameters.iCalUid, e);
811	  if (res && res.code && res.code !== 200) {
812	    return notify_('Could not switch the template — try again before previewing or sending.');
813	  }
814	  return CardService.newActionResponseBuilder().build();
815	}
816	
817	// ── Helpers ───────────────────────────────────────────────
818	function patchFromForm_(iCalUid, e) {
819	  var emails = (e.parameters.emails || '').split(',').filter(Boolean_);
820	  var inputs = formInputs_(e);
821	  // The template picker lives on the confirm card only; it's absent (empty) when this
822	  // runs from the roster card, so we leave emailTemplateKey untouched there. One choice
823	  // applies to the whole batch (templates are stored per-guest).
824	  var tmpl = formValue_(inputs['email_template']);
825	  var guests = emails.map(function (em) {
826	    var g = {
827	      email: em,
828	      include: formValue_(inputs['inc_' + em]) === 'on', // OFF switches are absent → false
829	      name: formValue_(inputs['name_' + em]),
830	      phone: formValue_(inputs['phone_' + em])
831	    };
832	    if (tmpl) g.emailTemplateKey = tmpl;
833	    return g;
834	  });
835	  return engineFetch_('/api/visitor/calendar/addon/draft', 'PATCH', { iCalUid: iCalUid, patch: { guests: guests } });
836	}
837	
838	// Confirm-card patch: persist ONLY the batch email-template choice. The confirm card
839	// has no include/name/phone widgets, so we must not derive (and overwrite) those here
840	// — only `email_template` is present. Absent/no-change picker → no-op.
841	function patchTemplateFromForm_(iCalUid, e) {
842	  var tmpl = formValue_(formInputs_(e)['email_template']);
843	  if (!tmpl) return; // no picker shown, or nothing to change
844	  var emails = (e.parameters.emails || '').split(',').filter(Boolean_);
845	  if (!emails.length) return;
846	  var guests = emails.map(function (em) { return { email: em, emailTemplateKey: tmpl }; });
847	  return engineFetch_('/api/visitor/calendar/addon/draft', 'PATCH', { iCalUid: iCalUid, patch: { guests: guests } });
848	}
849	
850	function formInputs_(e) {
851	  return (e.commonEventObject && e.commonEventObject.formInputs) || {};
852	}
853	function formValue_(input) {
854	  if (input && input.stringInputs && input.stringInputs.value && input.stringInputs.value.length) {
855	    return input.stringInputs.value[0];
856	  }
857	  return '';
858	}
859	function Boolean_(x) { return !!x; }
860	
861	function textPreview_(json) {
862	  var t = json.text || json.html || '';
863	  t = t.replace(/<[^>]+>/g, ' ').replace(/&nbsp;/g, ' ').replace(/\s+/g, ' ').trim();
864	  return t.length > 1200 ? t.substring(0, 1200) + '…' : t;
865	}
866	
867	function notify_(msg) {
868	  return CardService.newActionResponseBuilder()
869	    .setNotification(CardService.newNotification().setText(msg))
870	    .build();
871	}
872	
873	function errorCard_(msg) {
874	  return CardService.newCardBuilder()
875	    .setHeader(CardService.newCardHeader()
876	      .setTitle('Something went wrong')
877	      .setImageUrl(ADDON_ICON_URL))
878	    .addSection(CardService.newCardSection()
879	      .addWidget(CardService.newDecoratedText()
880	        .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.DESCRIPTION))
881	        .setText(msg)
882	        .setWrapText(true)))
883	    .build();
884	}
885

