/**
 * Auxilio Visitor — Google Calendar add-on (card-first).
 *
 * The whole host flow lives in this card; it calls office-ops-engine over HTTPS.
 * Engine contract: ../office-ops-engine/spec/2026-06-16_calendar_addon_register_endpoint.md
 *
 * Apps Script (GAS, V8) — flat global scope, no imports/modules.
 * First version: push with clasp, then refine in the Apps Script editor (it can run
 * and log there; it can't be run from the monorepo).
 */

// Engine base URL. Default = the local-tunnel domain (npm run backendtunnel).
// Must also be listed in appsscript.json → urlFetchWhitelist.
var ENGINE_BASE = 'https://unyearning-olympia-unclimactic.ngrok-free.dev';

// Appointy logo embedded as a base64 data URI (gradient original from appointy.svg).
// Source: appointy.svg (copied from visitor-web/public/, also in this repo).
// Used by setImageUrl() in all card headers.
var ADDON_ICON_URL = 'data:image/svg+xml;base64,REDACTED';

// Primary brand colour — used for filled buttons and accent text.
var BRAND_COLOR = '#92288E';

// Circular "workspace building" avatar (Lucide `building` on a muted grey circle),
// shown in place of the photo avatar for INTERNAL colleagues so the host can tell at
// a glance who's a same-office teammate (toggle-off by default) vs an outside guest.
var INTERNAL_ICON_URL = 'data:image/svg+xml;base64,REDACTED';

// ── Triggers ──────────────────────────────────────────────
function onCalendarEventOpen(e) { return [buildVisitorCard_(e)]; }
function onCalendarEventUpdate(e) { return [buildVisitorCard_(e)]; }

// Serves the branded icon SVG at ?asset=logo. ContentService.MimeType.XML is the
// closest available type to image/svg+xml in GAS. The manifest logoUrl below points
// to visitor-web instead, which nginx serves with the correct image/svg+xml header.
function doGet(e) {
  if (e && e.parameter && e.parameter.asset === 'logo') {
    var b64 = ADDON_ICON_URL.split(',')[1];
    var svgText = Utilities.newBlob(Utilities.base64Decode(b64)).getDataAsString();
    return ContentService.createTextOutput(svgText).setMimeType(ContentService.MimeType.XML);
  }
  return ContentService.createTextOutput('Auxilio Workspace Add-on');
}

// Three-dot menu → Sign out.
// NOTE: we deliberately do NOT call ScriptApp.invalidateAuth() — invalidating auth
// breaks every subsequent add-on invocation (incl. re-clicking this very item) with
// "Unspecified error invoking the add-on", because the platform can't run any
// function once authorization is cleared. A Calendar add-on also has no login page
// we can navigate to (Google only shows the consent prompt automatically on the next
// authorized open). So sign-out routes the user to the real, linkable destination:
// the Google Account permissions page, where they can remove access / switch account.
// Removing access there forces full re-consent the next time they open the add-on.
function onSignOut(e) {
  var card = CardService.newCardBuilder()
    .setHeader(CardService.newCardHeader()
      .setTitle('Sign out')
      .setImageUrl(ADDON_ICON_URL))
    .addSection(CardService.newCardSection()
      .addWidget(CardService.newDecoratedText()
        .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PERSON))
        .setText('Switch account or re-grant access')
        .setBottomLabel('Remove Auxilio Visitor from your Google account, then reopen the add-on — you\'ll be asked to sign in and grant access again.')
        .setWrapText(true))
      .addWidget(CardService.newTextButton()
        .setText('Manage access')
        .setTextButtonStyle(CardService.TextButtonStyle.FILLED)
        .setOpenLink(CardService.newOpenLink()
          .setUrl('https://myaccount.google.com/permissions'))))
    .build();
  return CardService.newUniversalActionResponseBuilder()
    .displayAddOnCards([card])
    .build();
}

function onHomepage(e) {
  var introSection = CardService.newCardSection()
    .addWidget(CardService.newTextParagraph()
      .setText('Open a calendar event and add guest to register visitor passes.'));

  var howSection = CardService.newCardSection()
    .setHeader('How it works')
    .addWidget(CardService.newDecoratedText()
      .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PERSON))
      .setText('Choose who gets a pass')
      .setBottomLabel('Toggle guests on or off from the event\'s attendee list.')
      .setWrapText(true))
    .addWidget(CardService.newDecoratedText()
      .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.INVITE))
      .setText('Review and send')
      .setBottomLabel('Edit names and phone numbers, preview the invite email, then send.')
      .setWrapText(true))
    .addWidget(CardService.newDecoratedText()
      .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.TICKET))
      .setText('Manage anytime')
      .setBottomLabel('Cancel or resend passes by toggling them off and on.')
      .setWrapText(true));

  var autoSyncSection = CardService.newCardSection()
    .addWidget(CardService.newDecoratedText()
      .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.STAR))
      .setText('Auto-sync')
      .setBottomLabel('Move or cancel a meeting event and passes update automatically.')
      .setWrapText(true));

  return CardService.newCardBuilder()
    .setHeader(CardService.newCardHeader()
      .setTitle('Auxilio Visitor')
      .setSubtitle('Manage visitors from your calendar')
      .setImageUrl(ADDON_ICON_URL))
    .addSection(introSection)
    .addSection(howSection)
    .addSection(autoSyncSection)
    .build();
}

// ── Engine HTTP ───────────────────────────────────────────
function engineFetch_(path, method, payload) {
  var options = {
    method: method,
    contentType: 'application/json',
    muteHttpExceptions: true,
    headers: {
      Authorization: 'Bearer ' + ScriptApp.getIdentityToken(),
      'ngrok-skip-browser-warning': 'true'
    }
  };
  if (payload) options.payload = JSON.stringify(payload);
  var res = UrlFetchApp.fetch(ENGINE_BASE + path, options);
  var json = {};
  try { json = JSON.parse(res.getContentText()); } catch (err) {}
  return { code: res.getResponseCode(), json: json };
}

// Resolve attendees + (best-effort) iCalUID/title/times for the open event.
// Attendees come from the add-on payload (currentEventAccess) — no API call needed.
// The Calendar API lookup enriches with the canonical iCalUID + title/times so the
// engine dedups with the .ics/OAuth paths; if it fails we fall back to the event id
// as the key so the flow still works.
function loadEvent_(e) {
  var cal = e.calendar || {};
  var calendarId = cal.calendarId;
  var eventId = cal.id;
  var payloadAtt = cal.attendees || [];
  var info = {
    iCalUid: eventId,
    providerEventId: eventId,
    keySource: 'eventId',
    title: '',
    start: null,
    end: null,
    attendees: mapAttendees_(payloadAtt),
    debug: ''
  };
  var ev = fetchEventWithRetry_(calendarId, eventId);
  info.gotEvent = !!ev;
  if (ev) {
    if (ev.iCalUID) { info.iCalUid = ev.iCalUID; info.keySource = 'iCalUID'; }
    info.title = ev.summary || '';
    info.start = ev.start ? (ev.start.dateTime || ev.start.date) : null;
    info.end = ev.end ? (ev.end.dateTime || ev.end.date) : null;
    var apiAtt = mapAttendees_(ev.attendees);
    if (info.attendees.length === 0 && apiAtt.length > 0) info.attendees = apiAtt;
  }
  info.debug = 'got=' + (!!ev) + ' key=' + info.keySource + ' start=' + (info.start || 'null') +
    ' cal=' + (calendarId || '?') + ' guests=' + info.attendees.length +
    (info.gotEvent ? '' : ' err=' + (_lastEventFetchErr || 'none'));
  return info;
}

// Resolve the event from the Calendar API, tolerating transient 404s. A freshly
// created event is eventually-consistent — Events.get can 404 for a second or two
// after the user adds it — and this is our ONLY source of event start/end (the add-on
// payload carries attendees but no times). So a miss here means a draft saved without
// times and a send that fails with EVENT_TIME_MISSING. Retry with backoff (~2.7s
// total) across the event's calendar and the primary calendar. Returns the event or null.
var _lastEventFetchErr = '';
function fetchEventWithRetry_(calendarId, eventId) {
  _lastEventFetchErr = '';
  var targets = [];
  if (calendarId) targets.push(calendarId);
  if (calendarId !== 'primary') targets.push('primary');
  // Common case (a saved, propagated event) returns on the first get with no sleep.
  // The retries only cover a just-created event that's still eventually-consistent;
  // ~0.85s total is enough to catch the usual ~1s propagation without making every
  // unsaved-event open feel sluggish (the card shows a "save first" banner anyway,
  // and onSaveAndSend re-resolves the time before the actual send).
  var backoffs = [250, 600]; // waits AFTER attempts 0,1 (3 attempts total)
  for (var attempt = 0; attempt <= backoffs.length; attempt++) {
    for (var t = 0; t < targets.length; t++) {
      try {
        var ev = Calendar.Events.get(targets[t], eventId);
        if (ev) return ev;
      } catch (err) {
        // Capture WHY (auth/scope vs 404) — a persistent failure here is the root of
        // "Could not read the event time"; the message tells us scope vs not-found.
        _lastEventFetchErr = (err && err.message ? String(err.message) : String(err)).slice(0, 140);
      }
    }
    if (attempt < backoffs.length) Utilities.sleep(backoffs[attempt]);
  }
  return null;
}

// Per-guest avatar: Gravatar keyed on the email (real photo if they have one),
// falling back to a coloured initials avatar (ui-avatars) when they don't. Rendered
// as a circular image icon. Image URLs are fetched by Google's client, so they
// don't need urlFetchWhitelist.
function avatarIcon_(email, name) {
  var initials = (name || email || '?').trim().charAt(0).toUpperCase() || '?';
  var fallback = 'https://ui-avatars.com/api/?name=' + encodeURIComponent(initials) +
    '&size=64&background=92288E&color=ffffff&bold=true';
  var url = 'https://www.gravatar.com/avatar/' + md5Hex_((email || '').trim().toLowerCase()) +
    '?s=64&d=' + encodeURIComponent(fallback);
  return CardService.newIconImage()
    .setIconUrl(url)
    .setImageCropType(CardService.ImageCropType.CIRCLE);
}

// Circular building icon for internal colleagues (see INTERNAL_ICON_URL).
function buildingIcon_() {
  return CardService.newIconImage()
    .setIconUrl(INTERNAL_ICON_URL)
    .setImageCropType(CardService.ImageCropType.CIRCLE);
}

// Minimal MD5 → lowercase hex (Gravatar needs MD5 of the email).
function md5Hex_(str) {
  var bytes = Utilities.computeDigest(Utilities.DigestAlgorithm.MD5, str, Utilities.Charset.UTF_8);
  var hex = '';
  for (var i = 0; i < bytes.length; i++) {
    var b = (bytes[i] + 256) % 256;
    hex += (b < 16 ? '0' : '') + b.toString(16);
  }
  return hex;
}

function mapAttendees_(list) {
  return (list || [])
    .filter(function (a) { return a && a.email && !a.self && !a.organizer && !a.resource; })
    .map(function (a) {
      // Google often sets displayName = the email for non-contacts → treat as no name.
      var nm = (a.displayName && a.displayName !== a.email) ? a.displayName : '';
      return { email: a.email, name: nm };
    });
}

// ── Card helpers ──────────────────────────────────────────

function statusLabel_(g) {
  if (g.status === 'sent')      return '<font color="#34a853">Pass sent</font>';
  if (g.status === 'cancelled') return '<font color="#ea4335">Cancelled — toggle on to resend</font>';
  if (g.include === false) {
    // Internal colleagues are off by default ON PURPOSE — say so instead of a bare
    // "No pass" that reads like something's missing.
    return g.internal
      ? '<font color="#5f6368">Internal</font>'
      : '<font color="#9aa0a6">No pass</font>';
  }
  return '<font color="' + BRAND_COLOR + '">Will get a pass</font>';
}

// Returns a coloured stat line: "3 guests · 2 sent · 1 pending"
function buildStatLine_(roster) {
  var total = roster.length;
  var sent = 0, pending = 0, cancelled = 0;
  for (var i = 0; i < roster.length; i++) {
    var g = roster[i];
    if (g.status === 'sent') sent++;
    else if (g.status === 'cancelled') cancelled++;
    else if (g.include !== false) pending++;
  }
  var parts = [total + (total === 1 ? ' guest' : ' guests')];
  if (sent)      parts.push('<font color="#34a853">' + sent + ' sent</font>');
  if (pending)   parts.push('<font color="' + BRAND_COLOR + '">' + pending + ' pending</font>');
  if (cancelled) parts.push('<font color="#ea4335">' + cancelled + ' cancelled</font>');
  return parts.join('  ·  ');
}

// The email template currently in effect for the batch: the first included guest's
// chosen template (templates are stored per-guest but picked once for the whole send),
// or '' to let the confirm card pre-select the engine default.
function currentTemplateKey_(roster) {
  for (var i = 0; i < roster.length; i++) {
    var g = roster[i];
    if (g.include !== false && g.emailTemplateKey) return g.emailTemplateKey;
  }
  return '';
}

// Returns "Meeting title · Wed 18 Jun, 3:00 PM" for the card subtitle.
function formatEventSubtitle_(ev) {
  if (!ev.start) return ev.title || '';
  try {
    var d = new Date(ev.start);
    var day  = d.toLocaleDateString('en-IN', { weekday: 'short', day: 'numeric', month: 'short' });
    var time = d.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit', hour12: true });
    var datePart = day + ', ' + time;
    return ev.title ? ev.title + '  ·  ' + datePart : datePart;
  } catch (err) {
    return ev.title || '';
  }
}

// ── Main card ─────────────────────────────────────────────
function buildVisitorCard_(e) {
  // Fast path: no external guests in the payload → render immediately without any
  // network call. Keeps empty events snappy so the loader never lingers.
  var cal = e.calendar || {};
  if (mapAttendees_(cal.attendees).length === 0) {
    return CardService.newCardBuilder()
      .setHeader(CardService.newCardHeader()
        .setTitle('Visitor passes')
        .setImageUrl(ADDON_ICON_URL))
      .addSection(CardService.newCardSection()
        .addWidget(CardService.newDecoratedText()
          .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PERSON))
          .setText('No guests yet')
          .setBottomLabel('Add a guest to this event.')
          .setWrapText(true)))
      .build();
  }

  var ev = loadEvent_(e);
  if (!ev.iCalUid) return errorCard_('No event id in payload (' + ev.debug + ') — save the event, then reopen.');

  var organizerEmail = (cal.organizer && cal.organizer.email) || '';
  var res = engineFetch_('/api/visitor/calendar/addon/draft', 'POST', {
    iCalUid: ev.iCalUid, providerEventId: ev.providerEventId, organizerEmail: organizerEmail,
    title: ev.title, start: ev.start, end: ev.end, attendees: ev.attendees
  });
  if (res.code === 401) return errorCard_('Not authorized. Check the engine\'s AUXILIO_WORKSPACE_OAUTH_CLIENT_ID.');
  if (res.code === 403) return errorCard_('Your domain is not allowed to host visits.');
  if (res.code !== 200) return errorCard_('Engine error ' + res.code + '. Try refreshing the page.');

  var draft = res.json;
  var roster = draft.roster || [];
  resolveAndStoreNames_(ev.iCalUid, roster);
  var managed = !!draft.materialized;

  var card = CardService.newCardBuilder()
    .setHeader(CardService.newCardHeader()
      .setTitle(managed ? 'Manage passes' : 'Visitor passes')
      .setSubtitle(formatEventSubtitle_(ev))
      .setImageUrl(ADDON_ICON_URL));

  if (roster.length === 0) {
    return card
      .addSection(CardService.newCardSection()
        .addWidget(CardService.newDecoratedText()
          .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PERSON))
          .setText('No guests yet')
          .setBottomLabel('Add a guest to this event.')
          .setWrapText(true)))
      .build();
  }

  // Honest up-front warning when the event isn't readable from the Calendar API yet
  // (almost always: a new event still in the create/edit form, not saved). Passes need
  // the event's time, which only exists once saved — so flag it now instead of failing
  // at Send. The roster (from the payload) still shows so the host sees who's invited.
  if (!ev.gotEvent) {
    card.addSection(CardService.newCardSection()
      .addWidget(CardService.newDecoratedText()
        .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.CLOCK))
        .setText('Save the event to send passes')
        .setBottomLabel('Passes use the event’s date and time, which we can only read once it’s saved. Click Save, then reopen this panel.')
        .setWrapText(true)));
  }

  // Stat summary at the top (non-collapsible)
  card.addSection(CardService.newCardSection()
    .addWidget(CardService.newTextParagraph().setText(buildStatLine_(roster))));

  // One collapsible section per guest. The toggle row is always visible;
  // name + phone inputs collapse under it to keep long rosters scannable.
  var emails = [];
  for (var i = 0; i < roster.length; i++) {
    var g = roster[i];
    emails.push(g.email);

    var mainText   = g.name || g.email;
    var bottomText = g.name
      ? (g.email + '  ·  ' + statusLabel_(g))
      : statusLabel_(g);

    var sw = CardService.newSwitch()
      .setFieldName('inc_' + g.email)
      .setValue('on')
      .setSelected(g.include !== false);

    // Internal colleagues get a building icon + an "Internal" overline so the host
    // can tell teammates (toggle-off by default) from outside guests at a glance.
    var isInternal = g.internal === true;
    var toggleRow = CardService.newDecoratedText()
      .setStartIcon(isInternal ? buildingIcon_() : avatarIcon_(g.email, g.name))
      .setText(mainText)
      .setBottomLabel(bottomText)
      .setWrapText(true)
      .setSwitchControl(sw);
    if (isInternal) toggleRow.setTopLabel('Internal · Workspace');

    var guestSection = CardService.newCardSection()
      .setCollapsible(true)
      .setNumUncollapsibleWidgets(1)
      // ── Toggle row — always visible ──────────────────
      .addWidget(toggleRow)
      // ── Name input — collapses ───────────────────────
      .addWidget(CardService.newTextInput()
        .setFieldName('name_' + g.email)
        .setTitle('Full name')
        .setValue(g.name || ''))
      // ── Phone label with icon — collapses ───────────
      .addWidget(CardService.newDecoratedText()
        .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PHONE))
        .setText('Phone number')
        .setWrapText(true))
      // ── Phone input — collapses ──────────────────────
      .addWidget(CardService.newTextInput()
        .setFieldName('phone_' + g.email)
        .setTitle('Phone')
        .setValue(g.phone || ''));

    card.addSection(guestSection);
  }

  // Thread the email-template choice to the confirm card via action params (which are
  // string-only). The picker + email preview now live on that review step, not here —
  // this screen stays focused on the one question that matters: who gets a pass.
  var emailTemplates = draft.emailTemplates || [];
  var params = {
    iCalUid: ev.iCalUid,
    emails: emails.join(','),
    templates: JSON.stringify(emailTemplates),
    currentTemplate: currentTemplateKey_(roster)
  };
  addCalendarSyncSection_(card, draft.calendarSync);

  // Single primary CTA pinned to the footer — always reachable without scrolling.
  // On an unsaved event (no readable time) the CTA says "Save event first" and just
  // reminds the host, instead of letting them walk into the confirm flow then fail at
  // send. Once they save, the eventUpdateTrigger re-renders this card and the CTA flips
  // to Review & send. Otherwise it opens the review/confirm card.
  var primaryButton = CardService.newTextButton()
    .setTextButtonStyle(CardService.TextButtonStyle.FILLED)
    .setBackgroundColor(BRAND_COLOR);
  if (!ev.gotEvent) {
    primaryButton.setText('Save event first')
      .setOnClickAction(CardService.newAction().setFunctionName('onNeedsSave'));
  } else {
    primaryButton.setText(managed ? 'Review & update' : 'Review & send')
      .setOnClickAction(CardService.newAction().setFunctionName('onReviewSend').setParameters(params));
  }
  card.setFixedFooter(CardService.newFixedFooter().setPrimaryButton(primaryButton));

  return card.build();
}

// Background auto-sync (move/delete). Only the *actionable* connect CTA renders on the
// event card; the "already on" reassurance lives on the homepage info only (see
// onHomepage's autoSyncSection) so a connected host's event card stays roster-focused.
function addCalendarSyncSection_(card, sync) {
  if (!sync || !sync.relevant) return;
  if (sync.connected) return;
  var section = CardService.newCardSection();
  if (sync.connectUrl) {
    section
      .addWidget(CardService.newDecoratedText()
        .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.CLOCK))
        .setText('Keep passes in sync')
        .setBottomLabel('Connect your calendar so moving or cancelling this meeting updates passes automatically — even when this panel is closed.')
        .setWrapText(true))
      .addWidget(CardService.newTextButton()
        .setText('Connect calendar')
        .setTextButtonStyle(CardService.TextButtonStyle.FILLED)
        .setBackgroundColor(BRAND_COLOR)
        .setOpenLink(CardService.newOpenLink()
          .setUrl(sync.connectUrl)
          .setOpenAs(CardService.OpenAs.OVERLAY)));
  }
  card.addSection(section);
}

// ── Actions ───────────────────────────────────────────────
// Same derivation the engine uses, so we can tell an auto-derived name from a real one.
function cardDeriveName_(email) {
  var local = (email.split('@')[0] || email);
  return local.replace(/[._-]+/g, ' ').replace(/\b\w/g, function (c) { return c.toUpperCase(); }).trim() || email;
}

// Contact-name lookups are the heaviest part of a fresh card open, so we cache each
// resolved name (incl. "no match", to avoid re-querying non-contacts) per user in
// CacheService. A repeat open of any event with the same guest is then zero network.
// TTL 6h: long enough that a meeting's roster never re-pays, short enough to pick up
// a newly-added contact within a day. Key is lowercased email (per-user cache).
var _CONTACT_CACHE_TTL = 21600; // 6h, in seconds
function _contactCacheKey_(email) { return 'cn_' + (email || '').toLowerCase(); }

// searchContacts/otherContacts.search need a one-time warmup (empty query) so the
// server-side index is populated before the real query. Done once per execution.
var _peopleWarmed = false;
function warmPeople_(headers, base) {
  if (_peopleWarmed) return;
  _peopleWarmed = true;
  try {
    UrlFetchApp.fetchAll([
      { url: base + 'people:searchContacts?query=&readMask=names,emailAddresses', headers: headers, muteHttpExceptions: true },
      { url: base + 'otherContacts:search?query=&readMask=names,emailAddresses', headers: headers, muteHttpExceptions: true }
    ]);
  } catch (err) {}
  Utilities.sleep(120); // brief settle so the freshly-warmed index is queryable
}

// Pull the display name for `email` out of a People search response, or '' if no
// result actually matches that address.
function extractPeopleName_(resp, email) {
  if (!resp || resp.getResponseCode() !== 200) return '';
  var results;
  try { results = (JSON.parse(resp.getContentText()).results) || []; }
  catch (err) { return ''; }
  for (var i = 0; i < results.length; i++) {
    var person = results[i].person || {};
    var emails = person.emailAddresses || [];
    var match = emails.some(function (em) { return (em.value || '').toLowerCase() === email.toLowerCase(); });
    if (match && person.names && person.names.length) return person.names[0].displayName || '';
  }
  return '';
}

// Resolve display names for several emails in ONE parallel batch (searchContacts +
// otherContacts.search per email via UrlFetchApp.fetchAll) instead of 2 serial calls
// each. Returns a map of lowercased email → name (absent when no contact matched).
function batchResolveNames_(emails) {
  var out = {};
  if (!emails.length) return out;
  var headers = { Authorization: 'Bearer ' + ScriptApp.getOAuthToken() };
  var base = 'https://people.googleapis.com/v1/';
  warmPeople_(headers, base);
  var requests = [], meta = [];
  for (var i = 0; i < emails.length; i++) {
    var q = encodeURIComponent(emails[i]);
    requests.push({ url: base + 'people:searchContacts?query=' + q + '&readMask=names,emailAddresses', headers: headers, muteHttpExceptions: true });
    meta.push(emails[i]);
    requests.push({ url: base + 'otherContacts:search?query=' + q + '&readMask=names,emailAddresses', headers: headers, muteHttpExceptions: true });
    meta.push(emails[i]);
  }
  var responses;
  try { responses = UrlFetchApp.fetchAll(requests); }
  catch (err) { return out; }
  for (var r = 0; r < responses.length; r++) {
    var key = meta[r].toLowerCase();
    if (out[key]) continue; // already matched from this email's other source
    var name = extractPeopleName_(responses[r], meta[r]);
    if (name) out[key] = name;
  }
  return out;
}

// For each guest whose name is still auto-derived, fill in the real contact name and
// PATCH it onto the draft (so the engine remembers it too). Cache hits skip the
// network entirely; only genuine misses hit the People API, all in one batch. Mutates
// roster.
function resolveAndStoreNames_(iCalUid, roster) {
  var cache = CacheService.getUserCache();
  var pending = [];   // roster entries still showing an auto-derived name
  var toLookup = [];  // emails with no cached answer → need a network lookup
  for (var i = 0; i < roster.length; i++) {
    var g = roster[i];
    if (g.name && g.name !== cardDeriveName_(g.email)) continue; // already a real name
    pending.push(g);
    var cached = cache.get(_contactCacheKey_(g.email));
    if (cached === null) toLookup.push(g.email); // unknown → look up
    else if (cached) g.name = cached;            // '' = known non-contact, leave derived
  }

  if (toLookup.length) {
    var resolved = batchResolveNames_(toLookup);
    for (var j = 0; j < toLookup.length; j++) {
      var name = resolved[toLookup[j].toLowerCase()] || '';
      cache.put(_contactCacheKey_(toLookup[j]), name, _CONTACT_CACHE_TTL); // cache hits AND misses
    }
    for (var k = 0; k < pending.length; k++) {
      var pg = pending[k];
      var rn = resolved[pg.email.toLowerCase()];
      if (rn) pg.name = rn; // reflect immediately in this render
    }
  }

  var patches = [];
  for (var m = 0; m < pending.length; m++) {
    var p = pending[m];
    if (p.name && p.name !== cardDeriveName_(p.email)) patches.push({ email: p.email, name: p.name });
  }
  if (patches.length) {
    engineFetch_('/api/visitor/calendar/addon/draft', 'PATCH', { iCalUid: iCalUid, patch: { guests: patches } });
  }
}

// Unsaved-event CTA: we can't read the event time until it's saved (Google doesn't
// put it in the add-on payload), so remind the host to save. Saving fires the
// eventUpdateTrigger, which re-renders this card with a working Review & send.
function onNeedsSave(e) {
  return notify_('Save the event first (click Save). The panel will update so you can send passes.');
}

// Review step: persist edits, then push a textual confirm card. Cards can't
// render HTML inline (that's the "Preview email" overlay link), so the review
// here is the recipient list + what will happen — the guard before sending.
function onReviewSend(e) {
  var iCalUid = e.parameters.iCalUid;
  patchFromForm_(iCalUid, e); // persist toggles/names/phones BEFORE leaving the form card
  var emails = (e.parameters.emails || '').split(',').filter(Boolean_);
  var inputs = formInputs_(e);
  var included = [];
  var excluded = [];
  for (var i = 0; i < emails.length; i++) {
    var em = emails[i];
    var on = formValue_(inputs['inc_' + em]) === 'on';
    var name = formValue_(inputs['name_' + em]) || em;
    (on ? included : excluded).push({ email: em, name: name });
  }
  if (!included.length) return notify_('Turn on at least one guest before sending.');
  return CardService.newActionResponseBuilder()
    .setNavigation(CardService.newNavigation().pushCard(buildConfirmCard_(e.parameters, included, excluded)))
    .build();
}

function buildConfirmCard_(params, included, excluded) {
  // Thread the first included guest to the confirm card's actions — the per-guest
  // switches don't exist here, so onPreview can't re-derive the target from the form.
  params.previewEmail = included.length ? included[0].email : '';
  var card = CardService.newCardBuilder()
    .setHeader(CardService.newCardHeader()
      .setTitle('Send ' + included.length + ' pass' + (included.length > 1 ? 'es' : '') + '?')
      .setImageUrl(ADDON_ICON_URL));
  var sec = CardService.newCardSection().setHeader('These guests get a pass');
  for (var i = 0; i < included.length; i++) {
    sec.addWidget(CardService.newDecoratedText()
      .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.INVITE))
      .setText(included[i].name)
      .setBottomLabel(included[i].email)
      .setWrapText(true));
  }
  card.addSection(sec);
  if (excluded.length) {
    var ex = CardService.newCardSection().setHeader('Skipped (no pass / cancelled if sent before)');
    for (var j = 0; j < excluded.length; j++) {
      ex.addWidget(CardService.newDecoratedText()
        .setText(excluded[j].name).setBottomLabel(excluded[j].email).setWrapText(true));
    }
    card.addSection(ex);
  }

  // Email section: template picker (only when there's a real choice) + preview. The
  // picker is per-send (one template for the whole batch); preview opens the REAL
  // branded HTML for the first included guest. Both read/write the same draft, so
  // pick → preview → send stays consistent.
  var templates = [];
  try { templates = JSON.parse(params.templates || '[]'); } catch (err) { templates = []; }
  var emailSec = CardService.newCardSection().setHeader('Email');
  if (templates.length >= 2) {
    var picker = CardService.newSelectionInput()
      .setType(CardService.SelectionInputType.DROPDOWN)
      .setTitle('Template')
      .setFieldName('email_template')
      // Persist the choice to the draft the moment it changes. The Preview link below
      // is pre-baked at card-build time, and the engine renders preview-html from the
      // draft LIVE — so persisting on change is what keeps the (unchanged) link
      // showing the newly-picked template, with no round-trip on the Preview click.
      .setOnChangeAction(CardService.newAction()
        .setFunctionName('onConfirmTemplateChange')
        .setParameters({ iCalUid: params.iCalUid, emails: params.emails }));
    var current = params.currentTemplate || '';
    for (var t = 0; t < templates.length; t++) {
      var tmpl = templates[t];
      var selected = current ? (tmpl.key === current) : (tmpl.isDefault === true);
      picker.addItem(tmpl.name || tmpl.key, tmpl.key, selected);
    }
    emailSec.addWidget(picker);
  }
  // Pre-bake the preview link NOW (mint the signed token at card-build time) and carry
  // it on the button via setOpenLink. That opens the popup directly on the user's click
  // instead of after a server round-trip (setOnClickAction → onPreview), which is what
  // the browser popup blocker was killing. Fall back to the action handler only if we
  // couldn't mint the link (e.g. token fetch failed) — that path may still get blocked.
  var previewBtn = CardService.newTextButton().setText('Preview email');
  var pvUrl = previewUrl_(params.iCalUid, params.previewEmail);
  if (pvUrl) {
    previewBtn.setOpenLink(CardService.newOpenLink()
      .setUrl(pvUrl)
      .setOpenAs(CardService.OpenAs.OVERLAY)
      .setOnClose(CardService.OnClose.NOTHING));
  } else {
    previewBtn.setOnClickAction(CardService.newAction().setFunctionName('onPreview').setParameters(params));
  }
  emailSec.addWidget(previewBtn);
  card.addSection(emailSec);

  card.setFixedFooter(CardService.newFixedFooter()
    .setPrimaryButton(CardService.newTextButton()
      .setText('Send passes')
      .setTextButtonStyle(CardService.TextButtonStyle.FILLED)
      .setBackgroundColor(BRAND_COLOR)
      .setOnClickAction(CardService.newAction().setFunctionName('onSaveAndSend').setParameters(params)))
    .setSecondaryButton(CardService.newTextButton()
      .setText('Back')
      .setOnClickAction(CardService.newAction().setFunctionName('onConfirmBack').setParameters(params))));
  return card.build();
}

function onConfirmBack(e) {
  return CardService.newActionResponseBuilder()
    .setNavigation(CardService.newNavigation().popCard())
    .build();
}

function onSaveAndSend(e) {
  var iCalUid = e.parameters.iCalUid;
  // Toggles/names/phones were already persisted by onReviewSend on the ROSTER card.
  // This runs from the CONFIRM card, which has none of those widgets — re-running
  // patchFromForm_ here would read empty inputs and wipe every guest to include=false
  // (the "No changes / No pass" bug). Only the (optional) template picker lives here.
  patchTemplateFromForm_(iCalUid, e);
  // Re-resolve event times here and send them along: if the draft-open missed them
  // (flaky Events.get on a just-created event), the draft would have no start/end and
  // the send would fail with EVENT_TIME_MISSING. Passing fresh times lets the engine
  // self-correct the draft instead of forcing the host to reopen.
  var ev = loadEvent_(e);
  // Times come only from Calendar.Events.get (the payload has none). If we still can't
  // read them, say exactly why instead of the engine's generic message — `got=false`
  // means the API call itself failed (scope/Advanced-Service/permission, not a timing
  // blip); `got=true start=null` means the event genuinely has no start.
  if (!ev.start || !ev.end) {
    // A 'Not Found' from Calendar.Events.get means the event isn't saved/propagated
    // yet — the panel shows attendees from the payload, but the event record (the only
    // source of start/end) doesn't exist server-side. Tell the host plainly.
    if (ev.debug.indexOf('Not Found') >= 0 || !ev.gotEvent) {
      return notify_('Save the event first (click Save), then reopen this panel and send. The pass time comes from the saved event.');
    }
    return notify_('Could not read the event time. Diagnostic: ' + ev.debug);
  }
  var res = engineFetch_('/api/visitor/calendar/addon/send', 'POST', {
    iCalUid: iCalUid, start: ev.start, end: ev.end
  });
  var msg;
  if (res.code === 200) {
    var sent = (res.json.created || []).length;
    var cancelled = (res.json.cancelled || []).length;
    var failed = res.json.failed || [];
    if (failed.length) {
      // Surface WHY a pass couldn't be sent (most often: event time in the past)
      // instead of silently leaving the guest pending.
      var reason = (failed[0] && failed[0].reason) || 'could not be sent';
      msg = "Couldn't send " + failed.length + ' pass' + (failed.length > 1 ? 'es' : '') + ': ' + reason;
    } else {
      var parts = [];
      if (sent) parts.push(sent + ' sent');
      if (cancelled) parts.push(cancelled + ' cancelled');
      msg = parts.length ? ('Passes updated: ' + parts.join(', ') + '.') : 'No changes.';
    }
  } else {
    msg = 'Update failed (' + res.code + ').';
  }
  // Re-render so the card switches to Manage mode and shows fresh statuses.
  return CardService.newActionResponseBuilder()
    .setNotification(CardService.newNotification().setText(msg))
    .setNavigation(CardService.newNavigation().updateCard(buildVisitorCard_(e)))
    .build();
}

function onPreview(e) {
  var iCalUid = e.parameters.iCalUid;
  // Runs from the CONFIRM card (no toggle/name/phone widgets) — persist only the
  // template choice; never re-derive include/name/phone here (would wipe the roster).
  patchTemplateFromForm_(iCalUid, e);
  // The included guests were already resolved on the roster card; onReviewSend threads
  // the first one through as previewEmail (the switches aren't on this card to read).
  var target = e.parameters.previewEmail || '';
  if (!target) return notify_('Turn on at least one guest to preview their email.');

  var pv = engineFetch_('/api/visitor/calendar/addon/preview', 'POST', { iCalUid: iCalUid, visitorEmail: target });
  if (pv.code !== 200 || !pv.json.previewToken) return notify_('Preview failed (' + pv.code + ').');

  // Open the REAL branded HTML in a popup overlay (the card can't render HTML).
  var url = ENGINE_BASE + '/api/visitor/calendar/addon/preview-html?t=' + encodeURIComponent(pv.json.previewToken);
  return CardService.newActionResponseBuilder()
    .setOpenLink(CardService.newOpenLink()
      .setUrl(url)
      .setOpenAs(CardService.OpenAs.OVERLAY)
      .setOnClose(CardService.OnClose.NOTHING))
    .build();
}

// Mint a preview-html URL (with a fresh signed token) at card-build time so the
// "Preview email" button can carry it via setOpenLink and open on the click itself
// — dodging the popup blocker that hits round-trip (setOnClickAction) opens. Returns
// '' if we can't mint a token, so the caller can fall back to the onPreview handler.
function previewUrl_(iCalUid, visitorEmail) {
  if (!iCalUid || !visitorEmail) return '';
  var pv = engineFetch_('/api/visitor/calendar/addon/preview', 'POST', { iCalUid: iCalUid, visitorEmail: visitorEmail });
  if (pv.code !== 200 || !pv.json.previewToken) return '';
  return ENGINE_BASE + '/api/visitor/calendar/addon/preview-html?t=' + encodeURIComponent(pv.json.previewToken);
}

// Template dropdown changed on the confirm card: persist the new choice to the draft.
// The Preview link is pre-baked and the token is template-agnostic (preview-html reads
// the draft live), so persisting here is all that's needed — no card rebuild, no new
// URL. Stay silent on success; only speak up if the persist failed.
function onConfirmTemplateChange(e) {
  var res = patchTemplateFromForm_(e.parameters.iCalUid, e);
  if (res && res.code && res.code !== 200) {
    return notify_('Could not switch the template — try again before previewing or sending.');
  }
  return CardService.newActionResponseBuilder().build();
}

// ── Helpers ───────────────────────────────────────────────
function patchFromForm_(iCalUid, e) {
  var emails = (e.parameters.emails || '').split(',').filter(Boolean_);
  var inputs = formInputs_(e);
  // The template picker lives on the confirm card only; it's absent (empty) when this
  // runs from the roster card, so we leave emailTemplateKey untouched there. One choice
  // applies to the whole batch (templates are stored per-guest).
  var tmpl = formValue_(inputs['email_template']);
  var guests = emails.map(function (em) {
    var g = {
      email: em,
      include: formValue_(inputs['inc_' + em]) === 'on', // OFF switches are absent → false
      name: formValue_(inputs['name_' + em]),
      phone: formValue_(inputs['phone_' + em])
    };
    if (tmpl) g.emailTemplateKey = tmpl;
    return g;
  });
  return engineFetch_('/api/visitor/calendar/addon/draft', 'PATCH', { iCalUid: iCalUid, patch: { guests: guests } });
}

// Confirm-card patch: persist ONLY the batch email-template choice. The confirm card
// has no include/name/phone widgets, so we must not derive (and overwrite) those here
// — only `email_template` is present. Absent/no-change picker → no-op.
function patchTemplateFromForm_(iCalUid, e) {
  var tmpl = formValue_(formInputs_(e)['email_template']);
  if (!tmpl) return; // no picker shown, or nothing to change
  var emails = (e.parameters.emails || '').split(',').filter(Boolean_);
  if (!emails.length) return;
  var guests = emails.map(function (em) { return { email: em, emailTemplateKey: tmpl }; });
  return engineFetch_('/api/visitor/calendar/addon/draft', 'PATCH', { iCalUid: iCalUid, patch: { guests: guests } });
}

function formInputs_(e) {
  return (e.commonEventObject && e.commonEventObject.formInputs) || {};
}
function formValue_(input) {
  if (input && input.stringInputs && input.stringInputs.value && input.stringInputs.value.length) {
    return input.stringInputs.value[0];
  }
  return '';
}
function Boolean_(x) { return !!x; }

function textPreview_(json) {
  var t = json.text || json.html || '';
  t = t.replace(/<[^>]+>/g, ' ').replace(/&nbsp;/g, ' ').replace(/\s+/g, ' ').trim();
  return t.length > 1200 ? t.substring(0, 1200) + '…' : t;
}

function notify_(msg) {
  return CardService.newActionResponseBuilder()
    .setNotification(CardService.newNotification().setText(msg))
    .build();
}

function errorCard_(msg) {
  return CardService.newCardBuilder()
    .setHeader(CardService.newCardHeader()
      .setTitle('Something went wrong')
      .setImageUrl(ADDON_ICON_URL))
    .addSection(CardService.newCardSection()
      .addWidget(CardService.newDecoratedText()
        .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.DESCRIPTION))
        .setText(msg)
        .setWrapText(true)))
    .build();
}

