// Three-dot menu → Sign out.
// NOTE: we deliberately do NOT call ScriptApp.invalidateAuth() — invalidating auth
// breaks every subsequent add-on invocation (incl. re-clicking this very item) with
// "Unspecified error invoking the add-on", because the platform can't run any
// function once authorization is cleared. A Calendar add-on also has no login page
// we can navigate to (Google only shows the consent prompt automatically on the next
// authorized open). So sign-out routes the user to the real, linkable destination:
// the Google Account permissions page, where they can remove access / switch account.
// Removing access there forces full re-consent the next time they open the add-on.
function onSignOut(e) {
  var card = CardService.newCardBuilder()
    .setHeader(CardService.newCardHeader()
      .setTitle('Sign out')
      .setImageUrl(ADDON_ICON_URL))
    .addSection(CardService.newCardSection()
      .addWidget(CardService.newDecoratedText()
        .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PERSON))
        .setText('Switch account or re-grant access')
        .setBottomLabel('Remove Auxilio Visitor from your Google account, then reopen the add-on — you\'ll be asked to sign in and grant access again.')
        .setWrapText(true))
      .addWidget(CardService.newTextButton()
        .setText('Manage access')
        .setTextButtonStyle(CardService.TextButtonStyle.FILLED)
        .setOpenLink(CardService.newOpenLink()
          .setUrl('https://myaccount.google.com/permissions'))))
    .build();
  return CardService.newUniversalActionResponseBuilder()
    .displayAddOnCards([card])
    .build();
}

