input.new_string:
// Sign out (homepage card button → onSignOut).
//
// WHY a card button, not the three-dot universal action: a UniversalActionResponse can
// only displayAddOnCards (which does NOT render in-panel for Calendar add-ons — it read
// as "nothing happens") or openLink (a jarring new browser tab). Neither gives an
// in-panel signed-out screen. A normal card Action CAN navigate the panel (pushCard /
// popCard — the same mechanism the rest of this add-on uses), so Sign out lives on the
// homepage card instead, where it can push the signed-out card reliably.
//
// WHAT "sign out" means here: a Workspace add-on has no login of its own — it runs as
// the Google account already signed into Calendar, authenticating via getIdentityToken().
// There is nothing we can clear from inside the add-on (and ScriptApp.invalidateAuth()
// is off-limits: it wedges every later invocation with "Unspecified error invoking the
// add-on"). So this is an in-panel affordance: the signed-out card explains that, offers
// "Sign in" (back to the add-on), and links to the Google Account permissions page for
// the only real actions — switch account / remove access (which forces re-consent on the
// next open).
function onSignOut(e) {
  return CardService.newActionResponseBuilder()
    .setNavigation(CardService.newNavigation().pushCard(buildSignedOutCard_()))
    .build();
}

// "Sign in" on the signed-out card: just return to where the user was (the card beneath
// the pushed signed-out card). Nothing was actually cleared, so there's nothing to
// re-establish — popping the card is the whole "sign back in".
function onSignIn(e) {
  return CardService.newActionResponseBuilder()
    .setNavigation(CardService.newNavigation().popCard())
    .build();
}

function buildSignedOutCard_() {
  return CardService.newCardBuilder()
    .setHeader(CardService.newCardHeader()
      .setTitle('Auxilio Visitor')
      .setImageUrl(ADDON_ICON_URL))
    .addSection(CardService.newCardSection()
      .addWidget(CardService.newDecoratedText()
        .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PERSON))
        .setText('You’re signed out')
        .setBottomLabel('Auxilio runs as your Google account. To use it again, tap Sign in.')
        .setWrapText(true))
      .addWidget(CardService.newTextButton()
        .setText('Sign in')
        .setTextButtonStyle(CardService.TextButtonStyle.FILLED)
        .setBackgroundColor(BRAND_COLOR)
        .setOnClickAction(CardService.newAction().setFunctionName('onSignIn'))))
    .addSection(CardService.newCardSection()
      .addWidget(CardService.newDecoratedText()
        .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PERSON))
        .setText('Switch account or remove access')
        .setBottomLabel('Opens your Google Account permissions, where you can remove Auxilio or switch which account it uses. Removing access asks you to grant it again next time.')
        .setWrapText(true))
      .addWidget(CardService.newTextButton()
        .setText('Manage access')
        .setOpenLink(CardService.newOpenLink()
          .setUrl('https://myaccount.google.com/permissions'))))
    .build();
}

