// Three-dot menu → Sign out. A universal action can only displayAddOnCards (show cards
// in-panel) or openLink (new browser tab); it can't pushCard/popCard. We use
// displayAddOnCards to replace the panel with the signed-out card — the in-panel result
// the user wants, without leaving Calendar.
//
// WHAT "sign out" means here: a Workspace add-on has no login of its own — it runs as
// the Google account already signed into Calendar, authenticating via getIdentityToken().
// We cannot clear that grant from inside the add-on (ScriptApp.invalidateAuth() wedges
// every later invocation with "Unspecified error invoking the add-on"), and there is no
// API to force Google's OAuth consent while the grant is valid. So this card explains
// that and links to the Google permissions page — the only place the grant is really
// removed, which is what makes the next open re-show consent.
function onSignOut(e) {
  return CardService.newUniversalActionResponseBuilder()
    .displayAddOnCards([buildSignedOutCard_()])
    .build();
}

// "Sign in" from the signed-out card: nothing was actually cleared, so re-render the
// homepage to drop the user back into the add-on.
function onSignIn(e) {
  return CardService.newActionResponseBuilder()
    .setNavigation(CardService.newNavigation().updateCard(onHomepage(e)))
    .build();
}

