input.new_string:
// Three-dot menu → Sign out. A universal action can only displayAddOnCards (show cards
// in-panel) or openLink (new browser tab); it can't pushCard/popCard. We use
// displayAddOnCards to replace the panel with the signed-out card — the in-panel result
// the user wants, without leaving Calendar.
//
// REAL sign-out: a Workspace add-on has no login of its own — it runs as the Google
// account already in Calendar, authenticating via getIdentityToken(). Google only shows
// its OAuth consent screen when the grant is missing/insufficient, and there's no API to
// force it while the grant is valid. So to make the NEXT open re-prompt for consent "as
// usual", we actually revoke the add-on's OAuth grant here (revokeGrant_ → Google's token
// revoke endpoint — the programmatic equivalent of "Remove access" on the permissions
// page). The signed-out card builds from static content (no OAuth needed), and the
// revoke runs after it's built, so this response still renders; the revoke only takes
// effect on the next invocation, where Google auto-shows the authorization prompt.
//
// NOTE: this is deliberately NOT ScriptApp.invalidateAuth(), which wedges later
// invocations with "Unspecified error invoking the add-on". A token revoke removes the
// grant cleanly so the platform re-prompts. If a future change ever does wedge the
// add-on, recover by re-granting from the Apps Script editor (Run any function → accept
// the auth dialog).
function onSignOut(e) {
  var card = buildSignedOutCard_();
  revokeGrant_(); // last: takes effect next invocation; this response still renders
  return CardService.newUniversalActionResponseBuilder()
    .displayAddOnCards([card])
    .build();
}

// Revoke the add-on's OAuth grant via Google's token-revoke endpoint (oauth2.googleapis
// .com/revoke, whitelisted in appsscript.json). Removing the grant is what makes the next
// add-on open show the real Google consent screen. Best-effort: returns true on a 200,
// false on any failure (network/non-200/throw) so the caller can keep going regardless.
function revokeGrant_() {
  try {
    var token = ScriptApp.getOAuthToken();
    var res = UrlFetchApp.fetch('https://oauth2.googleapis.com/revoke?token=' + encodeURIComponent(token), {
      method: 'post',
      contentType: 'application/x-www-form-urlencoded',
      muteHttpExceptions: true
    });
    return res.getResponseCode() === 200;
  } catch (err) {
    return false;
  }
}

// "Sign in" from the signed-out card. After onSignOut revoked the grant, this click is a
// fresh invocation against an unauthorized add-on — Google shows its real OAuth consent
// screen automatically BEFORE this runs. Once re-authorized, drop the user back into the
// add-on by re-rendering the homepage. (If the revoke had failed, the grant is still
// valid and this simply returns home — no consent, but no dead end.)
function onSignIn(e) {
  return CardService.newActionResponseBuilder()
    .setNavigation(CardService.newNavigation().updateCard(onHomepage(e)))
    .build();
}

function buildSignedOutCard_() {
  return CardService.newCardBuilder()
    .setHeader(CardService.newCardHeader()
      .setTitle('Auxilio Visitor')
      .setImageUrl(ADDON_ICON_URL))
    .addSection(CardService.newCardSection()
      .addWidget(CardService.newDecoratedText()
        .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PERSON))
        .setText('You’re signed out')
        .setBottomLabel('Access has been removed. Tap Sign in to grant access again — Google will ask you to confirm.')
        .setWrapText(true))
      .addWidget(CardService.newTextButton()
        .setText('Sign in')
        .setTextButtonStyle(CardService.TextButtonStyle.FILLED)
        .setBackgroundColor(BRAND_COLOR)
        .setOnClickAction(CardService.newAction().setFunctionName('onSignIn'))))
    .build();
}

