// fresh invocation against an unauthorized add-on — Google shows its real OAuth consent
// screen automatically BEFORE this runs. Once re-authorized, drop the user back into the
// add-on by re-rendering the homepage. (If the revoke had failed, the grant is still
// valid and this simply returns home — no consent, but no dead end.)
function onSignIn(e) {
  return CardService.newActionResponseBuilder()
    .setNavigation(CardService.newNavigation().updateCard(onHomepage(e)))
    .build();
}

