// actually invalidates the live token — its security benefit: a captured/cached token
// can't be reused afterward. Build the card FIRST (it needs no OAuth), then revoke, then
// return; the response still renders because it's already computed, and the revoke only
// bites on the next invocation.
//
// What this does NOT do (platform limits, not bugs): it can't force Google's consent
// screen on the next open — Apps Script keeps the user's app-level grant and silently
// re-mints a token (so the next open signs back in without re-consent). And it must NOT
// use ScriptApp.invalidateAuth(), which wedges every later invocation with "Unspecified
// error invoking the add-on". Forcing a fresh consent requires the user to click "Remove
// access" on their Google permissions page — the secondary link on the card.
function onSignOut(e) {
  var card = buildSignedOutCard_();
  revokeGrant_(); // last: invalidates the live token; this already-built response renders
  return CardService.newUniversalActionResponseBuilder()
    .displayAddOnCards([card])
    .build();
}

// Revoke the user's current OAuth access token via Google's revoke endpoint (whitelisted
// in appsscript.json). Best-effort: returns true on a 200, false on any failure so
// sign-out always completes. Only ever affects the current user's own token.
function revokeGrant_() {
  try {
    var token = ScriptApp.getOAuthToken();
    var res = UrlFetchApp.fetch('https://oauth2.googleapis.com/revoke?token=' + encodeURIComponent(token), {
      method: 'post',
      contentType: 'application/x-www-form-urlencoded',
      muteHttpExceptions: true
    });
    return res.getResponseCode() === 200;
  } catch (err) {
    return false;
  }
}

function buildSignedOutCard_() {
  return CardService.newCardBuilder()
    .setHeader(CardService.newCardHeader()
      .setTitle('Auxilio Visitor')
      .setImageUrl(ADDON_ICON_URL))
    .addSection(CardService.newCardSection()
      .addWidget(CardService.newDecoratedText()
        .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PERSON))
        .setText('You’re signed out')
        .setBottomLabel('Your access token has been revoked. Reopen Auxilio to use it again.')
        .setWrapText(true)))
    .addSection(CardService.newCardSection()
      .addWidget(CardService.newDecoratedText()
        .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PERSON))
        .setText('Remove access or switch account')
        .setBottomLabel('To fully disconnect Auxilio (Google will ask you to grant access again next time) or switch which account it uses, open your Google permissions.')
        .setWrapText(true))
      .addWidget(CardService.newTextButton()
        .setText('Manage access')
        .setOpenLink(CardService.newOpenLink()
          .setUrl('https://myaccount.google.com/permissions'))))
    .build();
}

