// ── App session (website-style sign in/out) ───────────────
// A Workspace add-on has no session of its own — it runs as the signed-in Google account
// and Google mints its token per execution, so there's nothing to "log out" at the auth
// layer (revoking/invalidating from inside breaks the add-on). Instead we keep OUR OWN
// session, exactly like a website keeps a session cookie: a per-user flag in
// UserProperties. Sign out sets it; every trigger gates on it and shows the signed-out
// card; Sign in clears it. This is a UX session, not a security revocation — the Google
// grant is untouched (for a real revoke the card links to "Manage access").
var _SESSION_SIGNED_OUT_KEY = 'auxilio.signedOut';
function isSignedOut_() {
  return PropertiesService.getUserProperties().getProperty(_SESSION_SIGNED_OUT_KEY) === '1';
}
function setSignedOut_() {
  PropertiesService.getUserProperties().setProperty(_SESSION_SIGNED_OUT_KEY, '1');
}
function clearSignedOut_() {
  PropertiesService.getUserProperties().deleteProperty(_SESSION_SIGNED_OUT_KEY);
}

// ── Triggers ──────────────────────────────────────────────
// Each trigger gates on our app session first: when signed out, show the signed-out card
// instead of the real one (the website "you must sign in" gate).
function onCalendarEventOpen(e) { return [isSignedOut_() ? buildSignedOutCard_() : buildVisitorCard_(e)]; }
function onCalendarEventUpdate(e) { return [isSignedOut_() ? buildSignedOutCard_() : buildVisitorCard_(e)]; }

