// Three-dot menu → Sign out. Sets our app-session flag, then shows the signed-out card
// in-panel (a universal action can only displayAddOnCards or openLink — displayAddOnCards
// gives the in-panel result). From here every trigger renders the gate until Sign in.
//
// This is an app-level session, NOT a Google sign-out: the grant stays (we don't revoke —
// invalidateAuth() wedges the add-on, and a token revoke breaks UrlFetchApp). For a real
// disconnect the card links to "Manage access".
function onSignOut(e) {
  setSignedOut_();
  return CardService.newUniversalActionResponseBuilder()
    .displayAddOnCards([buildSignedOutCard_()])
    .build();
}

// "Sign in" from the gate: clear the session flag and re-render the right card for the
// context — the visitor card if we're inside an event, otherwise the homepage. The
// trigger gates will already show the real card on any later open too.
function onSignIn(e) {
  clearSignedOut_();
  var card = (e && e.calendar) ? buildVisitorCard_(e) : onHomepage(e);
  return CardService.newActionResponseBuilder()
    .setNavigation(CardService.newNavigation().updateCard(card))
    .build();
}

function buildSignedOutCard_() {
  return CardService.newCardBuilder()
    .setHeader(CardService.newCardHeader()
      .setTitle('Auxilio Visitor')
      .setImageUrl(ADDON_ICON_URL))
    .addSection(CardService.newCardSection()
      .addWidget(CardService.newDecoratedText()
        .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PERSON))
        .setText('You’re signed out')
        .setBottomLabel('Tap Sign in to use Auxilio again.')
        .setWrapText(true))
      .addWidget(CardService.newTextButton()
        .setText('Sign in')
        .setTextButtonStyle(CardService.TextButtonStyle.FILLED)
        .setBackgroundColor(BRAND_COLOR)
        .setOnClickAction(CardService.newAction().setFunctionName('onSignIn'))))
    .addSection(CardService.newCardSection()
      .addWidget(CardService.newDecoratedText()
        .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PERSON))
        .setText('Remove access or switch account')
        .setBottomLabel('Signing out here just ends your Auxilio session. To fully disconnect Auxilio from your Google account or switch accounts, open your Google permissions.')
